#include <bits/stdc++.h>
using namespace std;
int n,r,a[22],vis[22];
void dfs(int pos) {
	if(pos>r) {
		for(int i=1; i<=r; i++) {
			cout<<setw(3)<<a[i];
		}
		cout<<"\n";
		return ;
	}
	for(int i=a[pos-1]+1; i<=n; i++) {
		a[pos]=i;
		dfs(pos+1);
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>r;
	dfs(1);
	return 0;
}
